            # Compute softmax probability distribution
            # Use negative distances as logits for softmax
            emp_ids_sorted = sorted(raw_confidences.keys())
            min_distances = np.array([
                raw_confidences[eid]['min_distance'] for eid in emp_ids_sorted
            ])

            # Softmax on negative distances (closer = higher probability)
            # Temperature parameter controls sharpness
            temperature = 0.1
            logits = -min_distances / temperature
            logits -= np.max(logits)  # numerical stability
            exp_logits = np.exp(logits)
            softmax_probs = exp_logits / np.sum(exp_logits)

            for idx, emp_id in enumerate(emp_ids_sorted):
                entry = raw_confidences[emp_id].copy()
                entry['softmax_probability'] = round(float(softmax_probs[idx]), 6)
                probability_distribution.append(entry)

            # Sort by confidence descending
            probability_distribution.sort(
                key=lambda x: x['softmax_probability'], reverse=True
            )

            # Determine best match
            best_match = probability_distribution[0] if probability_distribution else None
            top, left, bottom, right = face_location

