def _sanitize_string(s: str) -> str:
    """Sanitize input strings to prevent injection."""
    if not isinstance(s, str):
        raise ValueError("Expected string input")
    # Remove any non-alphanumeric characters except spaces, hyphens, underscores
    sanitized = ''.join(
        c for c in s if c.isalnum() or c in (' ', '-', '_', '.')
    )
    return sanitized[:256]  # Limit length


def _load_and_validate_image(file_path: str) -> Optional[Image.Image]:
    """Load and validate an image from file path."""
    try:
        # Resolve path and check for traversal
        resolved = Path(file_path).resolve()
        if not resolved.is_file():
            logger.warning(f"File does not exist: {file_path}")
            return None

        with Image.open(str(resolved)) as img:
            # Validate format
            if img.format not in ('JPEG', 'PNG'):
                logger.warning(f"Invalid image format: {img.format}")
                return None

            # Validate dimensions
            width, height = img.size
            if (width > MAX_IMAGE_DIMENSION or height > MAX_IMAGE_DIMENSION or
                    width < MIN_IMAGE_DIMENSION or height < MIN_IMAGE_DIMENSION):
                logger.warning(f"Invalid image dimensions: {width}x{height}")
                return None

            # Convert to RGB
            img = img.convert('RGB')
            return img.copy()

    except Exception as e:
        logger.error(f"Error loading image {file_path}: {e}")
        return None


def _load_and_validate_image_from_bytes(image_data: bytes) -> Optional[Image.Image]:
    """Load and validate an image from bytes."""
    try:
        if len(image_data) > 10 * 1024 * 1024:  # 10MB
            logger.warning("Image data too large")
            return None

        if len(image_data) < 100:
            logger.warning("Image data too small")
            return None

        with Image.open(BytesIO(image_data)) as img:
            if img.format not in ('JPEG', 'PNG'):
                logger.warning(f"Invalid image format: {img.format}")
                return None

            width, height = img.size
            if (width > MAX_IMAGE_DIMENSION or height > MAX_IMAGE_DIMENSION or
                    width < MIN_IMAGE_DIMENSION or height < MIN_IMAGE_DIMENSION):
                logger.warning(f"Invalid image dimensions: {width}x{height}")
                return None

            # Disable decompression bomb check for reasonable sizes
            # but we already checked dimensions
            img = img.convert('RGB')
            return img.copy()

    except Exception as e:
        logger.error(f"Error loading image from bytes: {e}")
        return None


# API Key management
class APIKeyManager:
    """Manages API keys for authentication."""

    def __init__(self, keys_path: str):
        self.keys_path = keys_path
        self.keys = {}
        self._load_keys()

    def _load_keys(self):
        if os.path.exists(self.keys_path):
            try:
                with open(self.keys_path, 'r') as f:
                    self.keys = json.load(f)
            except (json.JSONDecodeError, IOError) as e:
                logger.error(f"Failed to load API keys: {e}")
                self.keys = {}

    def _save_keys(self):
        temp_path = self.keys_path + '.tmp'
        with open(temp_path, 'w') as f:
            json.dump(self.keys, f, indent=2)
        os.replace(temp_path, self.keys_path)

    def generate_key(self, description: str, role: str = 'reader') -> dict:
        """Generate a new API key."""
        if role not in ('reader', 'admin'):
            raise ValueError("Role must be 'reader' or 'admin'")

        raw_key = secrets.token_urlsafe(48)
        key_hash = hashlib.sha256(raw_key.encode()).hexdigest()

        self.keys[key_hash] = {
            'description': _sanitize_string(description),
            'role': role,
            'created': datetime.utcnow().isoformat(),
            'active': True
        }
        self._save_keys()

        return {
            'api_key': raw_key,
            'key_hash': key_hash,
            'role': role,
            'description': description
        }

    def validate_key(self, raw_key: str) -> Optional[dict]:
        """Validate an API key and return its metadata."""
        if not raw_key or not isinstance(raw_key, str):
            return None

        key_hash = hashlib.sha256(raw_key.encode()).hexdigest()
        key_data = self.keys.get(key_hash)

        if key_data and key_data.get('active', False):
            return {
                'key_hash': key_hash,
                'role': key_data['role'],
                'description': key_data['description']
            }
        return None

    def revoke_key(self, key_hash: str) -> bool:
        """Revoke an API key by its hash."""
        if key_hash in self.keys:
            self.keys[key_hash]['active'] = False
            self._save_keys()
            return True
        return False


# Rate limiting (simple in-memory)
class RateLimiter:
    """Simple in-memory rate limiter."""

    def __init__(self, max_requests: int = 60, window_seconds: int = 60):
        self.max_requests = max_requests
        self.window_seconds = window_seconds
        self.requests: dict = {}

    def is_allowed(self, identifier: str) -> bool:
        now = datetime.utcnow()
        window_start = now - timedelta(seconds=self.window_seconds)

        if identifier not in self.requests:
            self.requests[identifier] = []

        # Clean old entries
        self.requests[identifier] = [
            ts for ts in self.requests[identifier] if ts > window_start
        ]

        if len(self.requests[identifier]) >= self.max_requests:
            return False

        self.requests[identifier].append(now)
        return True


