def require_auth(role: str = 'reader'):
    """Decorator to require API key authentication."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            api_key = request.headers.get('X-API-Key', '')

            if not api_key:
                logger.warning(
                    f"Unauthenticated request from {request.remote_addr}"
                )
                return jsonify({
                    'success': False,
                    'error': 'API key required. Provide X-API-Key header.'
                }), 401

            key_data = api_key_manager.validate_key(api_key)
            if not key_data:
                logger.warning(
                    f"Invalid API key from {request.remote_addr}"
                )
                return jsonify({
                    'success': False,
                    'error': 'Invalid or revoked API key.'
                }), 403

            # Check role
            if role == 'admin' and key_data['role'] != 'admin':
                logger.warning(
                    f"Insufficient permissions from {request.remote_addr}"
                )
                return jsonify({
                    'success': False,
                    'error': 'Insufficient permissions. Admin role required.'
                }), 403

            # Rate limiting
            identifier = key_data['key_hash']
            if not rate_limiter.is_allowed(identifier):
                logger.warning(f"Rate limit exceeded for {identifier}")
                return jsonify({
                    'success': False,
                    'error': 'Rate limit exceeded. Try again later.'
                }), 429

            g.api_key_data = key_data
            return f(*args, **kwargs)
        return decorated_function
    return decorator


