@app.route('/api/v1/recognize', methods=['POST'])
@require_auth(role='reader')
def recognize_face():
    """
    Recognize a face in an uploaded image.
    Returns confidence scores for all known employees.
    """
    if 'image' not in request.files:
        return jsonify({
            'success': False,
            'error': 'No image file provided. Use multipart form with "image" field.'
        }), 400

    file = request.files['image']

    if file.filename == '':
        return jsonify({
            'success': False,
            'error': 'No file selected.'
        }), 400

    # Validate filename
    filename = secure_filename(file.filename)
    if not filename:
        return jsonify({
            'success': False,
            'error': 'Invalid filename.'
        }), 400

    ext = filename.rsplit('.', 1)[-1].lower() if '.' in filename else ''
    if ext not in ALLOWED_EXTENSIONS:
        return jsonify({
            'success': False,
            'error': f'Invalid file type. Allowed: {", ".join(ALLOWED_EXTENSIONS)}'
        }), 400

    # Check MIME type
    if file.content_type not in ALLOWED_MIME_TYPES:
        return jsonify({
            'success': False,
            'error': f'Invalid MIME type. Allowed: {", ".join(ALLOWED_MIME_TYPES)}'
        }), 400

    # Get tolerance parameter
    tolerance = request.form.get('tolerance', 0.6)
    try:
        tolerance = float(tolerance)
        if not 0.1 <= tolerance <= 1.0:
            raise ValueError()
    except (ValueError, TypeError):
        return jsonify({
            'success': False,
            'error': 'Tolerance must be a float between 0.1 and 1.0'
        }), 400

    try:
        image_data = file.read()
        result = model.predict(image_data, tolerance=tolerance)

        logger.info(
            f"Recognition request from {g.api_key_data['description']}: "
            f"{result.get('faces_detected', 0)} faces detected"
        )

        status_code = 200 if result['success'] else 400
        return jsonify(result), status_code

    except Exception as e:
        logger.error(f"Recognition error: {e}")
        return jsonify({
            'success': False,
            'error': 'Internal error during recognition.'
        }), 500


