# Add security headers
@app.after_request
def add_security_headers(response):
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Content-Security-Policy'] = "default-src 'none'"
    response.headers['Strict-Transport-Security'] = (
        'max-age=31536000; includeSubDomains'
    )
    response.headers['Cache-Control'] = 'no-store, no-cache, must-revalidate'
    response.headers['Pragma'] = 'no-cache'
    return response


def initialize_system():
    """Initialize the system with a default admin key if none exist."""
    if not api_key_manager.keys:
        result = api_key_manager.generate_key('System Admin', 'admin')
        print("=" * 60)
        print("INITIAL ADMIN API KEY GENERATED")
        print(f"API Key: {result['api_key']}")
        print(f"Key Hash: {result['key_hash']}")
        print("STORE THIS KEY SECURELY - IT CANNOT BE RETRIEVED LATER")
        print("=" * 60)
        logger.info("Initial admin API key generated")

    # Create training data directory if it doesn't exist
    os.makedirs(app.config['TRAINING_DATA_PATH'], exist_ok=True)
    os.makedirs(app.config['UPLOAD_FOLDER'], exist_ok=True)


if __name__ == '__main__':
    initialize_system()

    # Auto-train if training data exists and model is empty
    if not model.known_encodings:
        training_path = Path(app.config['TRAINING_DATA_PATH'])
        if training_path.is_dir() and any(training_path.iterdir()):
            logger.info("Auto-training on existing training data...")
            stats = model.train_on_directory(str(training_path))
            logger.info(f"Auto-training complete: {stats}")

    # Run with SSL in production; here using debug=False for security
    app.run(
        host='127.0.0.1',
        port=int(os.environ.get('PORT', 5000)),
        debug=False
    )